/**
 * This script fixes the gql imports in the generated type files.
 * by importing gql from graphql-tag instead of @apollo/client.
 * Otherwise, when running Playwright tests there will be an error:
 *
 * "SyntaxError: The requested module '@apollo/client' does not provide an export named 'gql'"
 */
import fs from 'fs';
import path from 'path';

// Directory containing type files generated by "yarn codegen"
const codegenGeneratedDir = './src/generated/';

// Fix gql imports in generated type files
fs.readdirSync(codegenGeneratedDir).forEach((file) => {
  if (file.endsWith('.tsx') || file.endsWith('.ts')) {
    const filePath = path.join(codegenGeneratedDir, file);
    const origContent = fs.readFileSync(filePath, 'utf8');
    const fixedContent = origContent.replaceAll(
      "import { gql } from '@apollo/client';",
      "import { gql } from 'graphql-tag';"
    );
    fs.writeFileSync(filePath, fixedContent);

    // eslint-disable-next-line no-console
    console.info(`Fixed gql imports in ${file}`);
  }
});

// eslint-disable-next-line no-console
console.info('All gql imports fixed in generated type files.');
